3	import { revalidatePath } from "next/cache";
4	import { eq } from "drizzle-orm";
5	import db, { createDb } from "@/db";
6	import { todos } from "@/db/schema";
7	
8	export async function addTodoWithDb(
9	  database: ReturnType<typeof createDb>,
10	  title: string
11	): Promise<{ error: string | null }> {
12	  const trimmed = title.trim();
13	  if (!trimmed) return { error: "Title cannot be empty" };
14	  if (trimmed.length > 500) return { error: "Title must be 500 characters or less" };
15	
16	  database.insert(todos).values({ title: trimmed }).run();
17	  revalidatePath("/");
18	  return { error: null };
19	}
20	
21	export async function addTodo(
22	  _prevState: { error: string | null },
23	  formData: FormData
24	): Promise<{ error: string | null }> {
25	  const title = formData.get("title") as string;
26	  return addTodoWithDb(db, title ?? "");
27	}
28	
29	export async function toggleTodoWithDb(
30	  database: ReturnType<typeof createDb>,
31	  id: number
32	) {
33	  const existing = database
34	    .select()
35	    .from(todos)
36	    .where(eq(todos.id, id))
37	    .all();
38	  if (existing.length === 0) return;
39	
40	  const current = existing[0].completed;
41	  database
42	    .update(todos)
43	    .set({ completed: current === 0 ? 1 : 0 })
44	    .where(eq(todos.id, id))
45	    .run();
46	  revalidatePath("/");
47	}
48	
49	export async function toggleTodo(formData: FormData) {
50	  const id = Number(formData.get("id"));
51	  await toggleTodoWithDb(db, id);
52	}
53	
54	export async function deleteTodoWithDb(
55	  database: ReturnType<typeof createDb>,
56	  id: number
57	) {
58	  database.delete(todos).where(eq(todos.id, id)).run();
59	  revalidatePath("/");
60	}
61	
62	export async function deleteTodo(formData: FormData) {
63	  const id = Number(formData.get("id"));
64	  await deleteTodoWithDb(db, id);
65	}
