3	import { useActionState, useRef, useEffect } from "react";
4	import { addTodo } from "@/app/actions";
5	
6	export default function AddTodoForm() {
7	  const [state, formAction, isPending] = useActionState(addTodo, {
8	    error: null,
9	  });
10	  const inputRef = useRef<HTMLInputElement>(null);
11	  const prevStateRef = useRef(state);
12	
13	  useEffect(() => {
14	    if (prevStateRef.current !== state && state.error === null && inputRef.current) {
15	      inputRef.current.value = "";
16	      inputRef.current.focus();
17	    }
18	    prevStateRef.current = state;
19	  }, [state]);
20	
21	  return (
22	    <div className="mb-8">
23	      <form action={formAction} className="flex gap-2">
24	        <input
25	          ref={inputRef}
26	          type="text"
27	          name="title"
28	          placeholder="Add a todo..."
29	          autoFocus
30	          className="flex-1 rounded-md border border-gray-300 px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
31	        />
32	        <button
33	          type="submit"
34	          disabled={isPending}
35	          className="rounded-md bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50"
36	        >
37	          Add
38	        </button>
39	      </form>
40	      {state.error && (
41	        <p className="mt-2 text-sm text-red-600">{state.error}</p>
42	      )}
43	    </div>
44	  );
45	}
