1	import { drizzle } from "drizzle-orm/better-sqlite3";
2	import Database from "better-sqlite3";
3	import * as schema from "./schema";
4	
5	export function createDb(path?: string) {
6	  const sqlite = new Database(path ?? "./sqlite.db");
7	  const db = drizzle(sqlite, { schema });
8	
9	  // Ensure tables exist (for in-memory DBs used in tests)
10	  sqlite.exec(`
11	    CREATE TABLE IF NOT EXISTS todos (
12	      id INTEGER PRIMARY KEY AUTOINCREMENT,
13	      title TEXT NOT NULL,
14	      completed INTEGER NOT NULL DEFAULT 0,
15	      created_at TEXT NOT NULL DEFAULT (current_timestamp)
16	    )
17	  `);
18	
19	  return db;
20	}
21	
22	const db = createDb();
23	export default db;
